<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f4f6f9; color: #222; padding: 20px; max-width: 900px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 24px; font-size: 1.6rem; }
  h2 { font-size: 1.15rem; margin-bottom: 10px; color: #333; }

  /* Form */
  .form-section { background: #fff; border-radius: 8px; padding: 18px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,.08); }
  .form-row { display: flex; flex-wrap: wrap; gap: 10px; align-items: flex-end; margin-bottom: 10px; }
  .form-group { display: flex; flex-direction: column; gap: 4px; }
  .form-group label { font-size: .82rem; font-weight: 600; color: #555; }
  input, select { padding: 8px 10px; border: 1px solid #ccc; border-radius: 5px; font-size: .95rem; }
  input:focus, select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,.18); }
  #add-expense { padding: 8px 20px; background: #4a90d9; color: #fff; border: none; border-radius: 5px; font-size: .95rem; cursor: pointer; font-weight: 600; }
  #add-expense:hover { background: #3a7bc8; }
  #form-error { color: #d32f2f; font-size: .88rem; min-height: 1.2em; margin-top: 4px; }

  /* Filters */
  .filter-section { background: #fff; border-radius: 8px; padding: 14px 18px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,.08); display: flex; flex-wrap: wrap; gap: 12px; align-items: flex-end; }
  .filter-section .form-group { min-width: 120px; }

  /* Summary */
  .summary-section { background: #fff; border-radius: 8px; padding: 14px 18px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,.08); }
  .summary-row { display: flex; flex-wrap: wrap; gap: 14px; align-items: center; }
  .cat-total { background: #eef3f9; padding: 6px 14px; border-radius: 5px; font-size: .9rem; font-weight: 600; }
  #total { background: #2e7d32; color: #fff; padding: 8px 18px; border-radius: 5px; font-size: 1.1rem; font-weight: 700; }

  /* Expense list */
  .list-section { background: #fff; border-radius: 8px; padding: 14px 18px; box-shadow: 0 1px 4px rgba(0,0,0,.08); }
  table { width: 100%; border-collapse: collapse; }
  th { text-align: left; font-size: .82rem; color: #666; text-transform: uppercase; letter-spacing: .04em; padding: 8px 6px; border-bottom: 2px solid #e0e0e0; }
  td { padding: 10px 6px; border-bottom: 1px solid #f0f0f0; font-size: .93rem; vertical-align: middle; }
  tr.expense:last-child td { border-bottom: none; }
  tr.expense.hidden { display: none; }
  .exp-del { background: #e53935; color: #fff; border: none; border-radius: 4px; padding: 4px 12px; cursor: pointer; font-size: .82rem; font-weight: 600; }
  .exp-del:hover { background: #c62828; }
  .amount-cell { font-weight: 700; color: #2e7d32; }
  .empty-msg { text-align: center; color: #999; padding: 24px; font-style: italic; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<div class="form-section">
  <h2>Add Expense</h2>
  <div class="form-row">
    <div class="form-group">
      <label for="amount">Amount</label>
      <input type="number" id="amount" min="0" step="any" placeholder="0.00">
    </div>
    <div class="form-group">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. Weekly shopping">
    </div>
  </div>
  <button id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</div>

<!-- Filters -->
<div class="filter-section">
  <h2 style="width:100%">Filters</h2>
  <div class="form-group">
    <label for="filter-category">Category</label>
    <select id="filter-category">
      <option value="all">all</option>
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>
  </div>
  <div class="form-group">
    <label for="filter-from">From</label>
    <input type="date" id="filter-from">
  </div>
  <div class="form-group">
    <label for="filter-to">To</label>
    <input type="date" id="filter-to">
  </div>
</div>

<!-- Summary -->
<div class="summary-section">
  <h2>Summary</h2>
  <div class="summary-row" id="summary-row"></div>
</div>

<!-- Expense List -->
<div class="list-section">
  <h2>Expenses</h2>
  <table>
    <thead>
      <tr>
        <th>Date</th>
        <th>Category</th>
        <th>Note</th>
        <th>Amount</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>
</div>

<script>
(function() {
  // --- State ---
  var STORAGE_KEY = 'expense_tracker_data';
  var expenses = [];

  // --- DOM refs ---
  var amountInput = document.getElementById('amount');
  var categorySelect = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var addBtn = document.getElementById('add-expense');
  var formError = document.getElementById('form-error');
  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');
  var expenseList = document.getElementById('expense-list');
  var totalEl = document.getElementById('total');
  var summaryRow = document.getElementById('summary-row');

  // --- Helpers ---
  function loadExpenses() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        expenses = JSON.parse(raw);
      }
    } catch(e) { expenses = []; }
  }

  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  function generateId() {
    return Date.now().toString(36) + Math.random().toString(36).substr(2, 5);
  }

  function formatAmount(n) {
    return n.toFixed(2);
  }

  function formatDate(dateStr) {
    if (!dateStr) return '';
    var parts = dateStr.split('-');
    return parts[2] + '/' + parts[1] + '/' + parts[0];
  }

  // --- Validation ---
  function validate() {
    var val = amountInput.value.trim();
    var dateVal = dateInput.value.trim();

    if (val === '' || dateVal === '') {
      formError.textContent = 'Please enter both an amount and a date.';
      return false;
    }

    var num = Number(val);
    if (isNaN(num) || num <= 0) {
      formError.textContent = 'Amount must be a positive number greater than zero.';
      return false;
    }

    formError.textContent = '';
    return true;
  }

  // --- Add expense ---
  addBtn.addEventListener('click', function() {
    if (!validate()) return;

    var expense = {
      id: generateId(),
      amount: parseFloat(amountInput.value),
      category: categorySelect.value,
      date: dateInput.value.trim(),
      note: noteInput.value.trim()
    };

    expenses.push(expense);
    saveExpenses();

    // Clear amount field and error
    amountInput.value = '';
    formError.textContent = '';

    render();
  });

  // --- Delete expense ---
  expenseList.addEventListener('click', function(e) {
    if (e.target.classList.contains('exp-del')) {
      var row = e.target.closest('.expense');
      var id = row.getAttribute('data-id');
      expenses = expenses.filter(function(exp) { return exp.id !== id; });
      saveExpenses();
      render();
    }
  });

  // --- Filters ---
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // --- Render ---
  function render() {
    var catFilter = filterCategory.value;
    var fromFilter = filterFrom.value;
    var toFilter = filterTo.value;

    // Sort newest first
    var sorted = expenses.slice().sort(function(a, b) {
      if (b.date !== a.date) return b.date.localeCompare(a.date);
      return b.id.localeCompare(a.id);
    });

    // Filter
    var visible = sorted.filter(function(exp) {
      if (catFilter !== 'all' && exp.category !== catFilter) return false;
      if (fromFilter && exp.date < fromFilter) return false;
      if (toFilter && exp.date > toFilter) return false;
      return true;
    });

    // Build list
    expenseList.innerHTML = '';
    if (visible.length === 0) {
      expenseList.innerHTML = '<tr><td colspan="5" class="empty-msg">No expenses to display.</td></tr>';
    } else {
      visible.forEach(function(exp) {
        var tr = document.createElement('tr');
        tr.className = 'expense';
        tr.setAttribute('data-id', exp.id);
        tr.innerHTML =
          '<td>' + formatDate(exp.date) + '</td>' +
          '<td>' + exp.category + '</td>' +
          '<td>' + (exp.note || '') + '</td>' +
          '<td class="amount-cell">' + formatAmount(exp.amount) + '</td>' +
          '<td><button class="exp-del">Delete</button></td>';
        expenseList.appendChild(tr);
      });
    }

    // Total of visible
    var total = visible.reduce(function(sum, exp) { return sum + exp.amount; }, 0);
    totalEl.textContent = 'Total: ' + formatAmount(total);

    // Per-category summary (of visible expenses)
    var cats = ['groceries', 'transport', 'bills', 'fun'];
    summaryRow.innerHTML = '';
    cats.forEach(function(cat) {
      var catTotal = visible.filter(function(exp) { return exp.category === cat; })
                            .reduce(function(s, exp) { return s + exp.amount; }, 0);
      var div = document.createElement('div');
      div.className = 'cat-total';
      div.setAttribute('data-cat', cat);
      div.textContent = cat + ': ' + formatAmount(catTotal);
      summaryRow.appendChild(div);
    });
  }

  // --- Init ---
  loadExpenses();
  render();
})();
</script>

</body>
</html>
